using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// --- Notes storage (shared across tool invocations) ---
var notes = new ResearchNotes();

// --- Define tools ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
    AIFunctionFactory.Create(notes.SaveNote),
    AIFunctionFactory.Create(notes.GetAllNotes),
};

// --- Build the chat client with function-calling support ---
IChatClient chatClient = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
    .UseFunctionInvocation(o => o.MaximumIterationsPerRequest = 15)
    .Build();

// --- Create the research agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to thoroughly research a topic
        using web search, take organized notes on key findings, and then
        produce a comprehensive summary.

        Follow this workflow:
        1. Break the topic into key subtopics or questions.
        2. Search the web for each subtopic (use varied queries for breadth).
        3. Save important findings as notes with descriptive titles.
        4. After gathering enough information, retrieve all your notes.
        5. Produce a well-structured summary with sections and source context.

        Be thorough but concise. Search at least 3 different queries.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics via web search and summarizes findings.");

// --- Get topic from user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent with streaming output ---
var session = await agent.CreateSessionAsync("research-session");

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session))
{
    if (update.Role == ChatRole.Assistant && !string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine("\n\n✅ Research complete.");

// ---------------------------------------------------------------------------
// Tool: Web Search (uses DuckDuckGo HTML — no API key required)
// ---------------------------------------------------------------------------
static partial class WebSearchTool
{
    private static readonly HttpClient s_httpClient = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [GeneratedRegex(
        @"class=""result__snippet""[^>]*>(.*?)</",
        RegexOptions.Singleline)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex(
        @"class=""result__a""[^>]*href=""([^""]+)""[^>]*>(.*?)</a>",
        RegexOptions.Singleline)]
    private static partial Regex LinkRegex();

    [Description("Search the web for information. Returns ranked result snippets.")]
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query,
        [Description("Max results to return (1-10)")] int maxResults = 5)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);

        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await s_httpClient.GetStringAsync(url);

            var snippets = SnippetRegex().Matches(html);
            var links = LinkRegex().Matches(html);

            if (snippets.Count == 0)
                return $"No results found for: {query}";

            var results = new List<string>();
            for (int i = 0; i < Math.Min(snippets.Count, maxResults); i++)
            {
                var snippet = WebUtility.HtmlDecode(
                    Regex.Replace(snippets[i].Groups[1].Value, "<.*?>", "")).Trim();

                var source = i < links.Count
                    ? WebUtility.HtmlDecode(
                        Regex.Replace(links[i].Groups[2].Value, "<.*?>", "")).Trim()
                    : "Unknown source";

                if (!string.IsNullOrWhiteSpace(snippet))
                    results.Add($"{results.Count + 1}. [{source}] {snippet}");
            }

            return results.Count > 0
                ? $"Search results for '{query}':\n{string.Join("\n\n", results)}"
                : $"No usable results found for: {query}";
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}";
        }
    }
}

// ---------------------------------------------------------------------------
// Tool: Note-Taking
// ---------------------------------------------------------------------------
class ResearchNotes
{
    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];

    [Description("Save a research note. Use to record important findings from searches.")]
    public string SaveNote(
        [Description("Short descriptive title for the note")] string title,
        [Description("The note content — key facts, quotes, or insights")] string content)
    {
        _notes.Add((title, content, DateTime.UtcNow));
        Console.ForegroundColor = ConsoleColor.DarkCyan;
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        Console.ResetColor();
        return $"Note saved: \"{title}\" (total: {_notes.Count})";
    }

    [Description("Retrieve all saved research notes to review before writing a summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"=== Note {i + 1}: {n.Title} ({n.Timestamp:HH:mm:ss} UTC) ===\n{n.Content}"));
    }
}

using System.ComponentModel;
